"""
Parameterized generator for GH351_prisma_29307.

Source PR:    https://github.com/prisma/prisma/pull/29307
Source Issue: N/A

Seed varies: renames 'case' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH351_prisma_29307'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH351_prisma_29307'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('case', 'case' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH351_prisma_29307',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'prisma/prisma',
                "pr_number": 29307,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/prisma/prisma/pull/29307",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'packages/adapter-pg/src/__tests__/errors.test.ts': 'import { describe, expect, it } from \'vitest\'\n\nimport { convertDriverError } from \'../errors\'\n\ndescribe(\'convertDriverError\', () => {\n  it(\'should handle LengthMismatch (22001)\', () => {\n    const error = { code: \'22001\', column: \'foo\', message: \'msg\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'LengthMismatch\',\n      column: \'foo\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle ValueOutOfRange (22003)\', () => {\n    const error = { code: \'22003\', message: \'out of range\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'ValueOutOfRange\',\n      cause: \'out of range\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle InvalidInputValue (22P02)\', () => {\n    const error = { code: \'22P02\', message: \'invalid input value for enum "Status": "INVALID"\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'InvalidInputValue\',\n      message: \'invalid input value for enum "Status": "INVALID"\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle UniqueConstraintViolation (23505)\', () => {\n    const error = { code: \'23505\', message: \'msg\', severity: \'ERROR\', detail: \'Key (id)\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'UniqueConstraintViolation\',\n      constraint: { fields: [\'id\'] },\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle NullConstraintViolation (23502)\', () => {\n    const error = { code: \'23502\', message: \'msg\', severity: \'ERROR\', detail: \'Key (foo)\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'NullConstraintViolation\',\n      constraint: { fields: [\'foo\'] },\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle ForeignKeyConstraintViolation (23503) with column\', () => {\n    const error = { code: \'23503\', message: \'msg\', severity: \'ERROR\', column: \'bar\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'ForeignKeyConstraintViolation\',\n      constraint: { fields: [\'bar\'] },\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle ForeignKeyConstraintViolation (23503) with constraint\', () => {\n    const error = { code: \'23503\', message: \'msg\', severity: \'ERROR\', constraint: \'baz\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'ForeignKeyConstraintViolation\',\n      constraint: { index: \'baz\' },\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle DatabaseDoesNotExist (3D000)\', () => {\n    const error = { code: \'3D000\', message: \'database "mydb" does not exist\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'DatabaseDoesNotExist\',\n      db: \'mydb\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle DatabaseAccessDenied (28000)\', () => {\n    const error = {\n      code: \'28000\',\n      message: \'no pg_hba.conf entry for host "172.20.20.2", user "db_user", database "prisma_db", no encryption\',\n      severity: \'FATAL\',\n    }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'DatabaseAccessDenied\',\n      db: \'prisma_db\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle AuthenticationFailed (28P01)\', () => {\n    const error = { code: \'28P01\', message: \'password authentication failed for user "root"\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'AuthenticationFailed\',\n      user: \'root\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle TransactionWriteConflict (40001)\', () => {\n    const error = { code: \'40001\', message: \'msg\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'TransactionWriteConflict\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle TableDoesNotExist (42P01)\', () => {\n    const error = { code: \'42P01\', message: \'relation "mytable" does not exist\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'TableDoesNotExist\',\n      table: \'mytable\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle ColumnNotFound (42703)\', () => {\n    const error = { code: \'42703\', message: \'column "foo" does not exist\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'ColumnNotFound\',\n      column: \'foo\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle DatabaseAlreadyExists (42P04)\', () => {\n    const error = { code: \'42P04\', message: \'database "mydb" already exists\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'DatabaseAlreadyExists\',\n      db: \'mydb\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should handle TooManyConnections (53300)\', () => {\n    const error = { code: \'53300\', message: \'too many connections\', severity: \'ERROR\' }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'TooManyConnections\',\n      cause: \'too many connections\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it.each([\n    [\'UNABLE_TO_VERIFY_LEAF_SIGNATURE\', \'unable to verify the first certificate\'],\n    [\n      \'ERR_TLS_CERT_ALTNAME_INVALID\',\n      `Hostname/IP does not match certificate\'s altnames: Host: localhost. is not in the cert\'s altnames: DNS:*.localdev.com`,\n    ],\n    [undefined, \'The server does not support SSL connections\'],\n  ])(\'should handle TLS error code %s\', (code, message) => {\n    const error = { code, message }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'TlsConnectionError\',\n      reason: message,\n    })\n  })\n\n  it.each([\n    [\'ENOTFOUND\', \'DatabaseNotReachable\', \'getaddrinfo ENOTFOUND locohost\'],\n    [\'ECONNREFUSED\', \'DatabaseNotReachable\', `connect ECONNREFUSED 127.0.0.1:6699`],\n    [\'ECONNRESET\', \'ConnectionClosed\', \'read ECONNRESET\'],\n    [\'ETIMEDOUT\', \'SocketTimeout\', \'connect ETIMEDOUT 127.0.0.1:9100\'],\n  ])(\'should handle socket error code %s\', (code, kind, message) => {\n    const error = { code, message, syscall: \'syscallname\', errno: -1 }\n    expect(convertDriverError(error)).toEqual({\n      kind,\n    })\n  })\n\n  it(\'should handle default (unknown code)\', () => {\n    const error = {\n      code: \'99999\',\n      message: \'unknown\',\n      severity: \'FATAL\',\n      detail: \'details\',\n      column: \'col\',\n      hint: \'hint\',\n    }\n    expect(convertDriverError(error)).toEqual({\n      kind: \'postgres\',\n      code: \'99999\',\n      severity: \'FATAL\',\n      message: \'unknown\',\n      detail: \'details\',\n      column: \'col\',\n      hint: \'hint\',\n      originalCode: error.code,\n      originalMessage: error.message,\n    })\n  })\n\n  it(\'should throw if not a db error\', () => {\n    expect(() => convertDriverError({ message: \'Unknown driver message\' })).toThrow()\n  })\n})\n',
            'packages/adapter-pg/src/errors.ts': 'import { Error as DriverAdapterErrorObject, MappedError } from \'@prisma/driver-adapter-utils\'\nimport type { DatabaseError } from \'pg\'\n\nconst TLS_ERRORS = new Set([\n  \'UNABLE_TO_GET_ISSUER_CERT\',\n  \'UNABLE_TO_GET_CRL\',\n  \'UNABLE_TO_DECRYPT_CERT_SIGNATURE\',\n  \'UNABLE_TO_DECRYPT_CRL_SIGNATURE\',\n  \'UNABLE_TO_DECODE_ISSUER_PUBLIC_KEY\',\n  \'CERT_SIGNATURE_FAILURE\',\n  \'CRL_SIGNATURE_FAILURE\',\n  \'CERT_NOT_YET_VALID\',\n  \'CERT_HAS_EXPIRED\',\n  \'CRL_NOT_YET_VALID\',\n  \'CRL_HAS_EXPIRED\',\n  \'ERROR_IN_CERT_NOT_BEFORE_FIELD\',\n  \'ERROR_IN_CERT_NOT_AFTER_FIELD\',\n  \'ERROR_IN_CRL_LAST_UPDATE_FIELD\',\n  \'ERROR_IN_CRL_NEXT_UPDATE_FIELD\',\n  \'DEPTH_ZERO_SELF_SIGNED_CERT\',\n  \'SELF_SIGNED_CERT_IN_CHAIN\',\n  \'UNABLE_TO_GET_ISSUER_CERT_LOCALLY\',\n  \'UNABLE_TO_VERIFY_LEAF_SIGNATURE\',\n  \'CERT_CHAIN_TOO_LONG\',\n  \'CERT_REVOKED\',\n  \'INVALID_CA\',\n  \'INVALID_PURPOSE\',\n  \'CERT_UNTRUSTED\',\n  \'CERT_REJECTED\',\n  \'HOSTNAME_MISMATCH\',\n  \'ERR_TLS_CERT_ALTNAME_FORMAT\',\n  \'ERR_TLS_CERT_ALTNAME_INVALID\',\n])\n\nconst SOCKET_ERRORS = new Set([\'ENOTFOUND\', \'ECONNREFUSED\', \'ECONNRESET\', \'ETIMEDOUT\'])\n\nexport function convertDriverError(error: unknown): DriverAdapterErrorObject {\n  if (isSocketError(error)) {\n    return mapSocketError(error)\n  }\n\n  if (isTlsError(error)) {\n    return {\n      kind: \'TlsConnectionError\',\n      reason: error.message,\n    }\n  }\n\n  if (isDriverError(error)) {\n    return {\n      originalCode: error.code,\n      originalMessage: error.message,\n      ...mapDriverError(error),\n    }\n  }\n\n  throw error\n}\n\nfunction mapDriverError(error: DatabaseError): MappedError {\n  switch (error.code) {\n    case \'22001\':\n      return {\n        kind: \'LengthMismatch\',\n        column: error.column,\n      }\n    case \'22003\':\n      return {\n        kind: \'ValueOutOfRange\',\n        cause: error.message,\n      }\n    case \'22P02\':\n      return {\n        kind: \'InvalidInputValue\',\n        message: error.message,\n      }\n    case \'23505\': {\n      const fields = error.detail\n        ?.match(/Key \\(([^)]+)\\)/)\n        ?.at(1)\n        ?.split(\', \')\n      return {\n        kind: \'UniqueConstraintViolation\',\n        constraint: fields !== undefined ? { fields } : undefined,\n      }\n    }\n    case \'23502\': {\n      const fields = error.detail\n        ?.match(/Key \\(([^)]+)\\)/)\n        ?.at(1)\n        ?.split(\', \')\n      return {\n        kind: \'NullConstraintViolation\',\n        constraint: fields !== undefined ? { fields } : undefined,\n      }\n    }\n    case \'23503\': {\n      let constraint: { fields: string[] } | { index: string } | undefined\n\n      if (error.column) {\n        constraint = { fields: [error.column] }\n      } else if (error.constraint) {\n        constraint = { index: error.constraint }\n      }\n\n      return {\n        kind: \'ForeignKeyConstraintViolation\',\n        constraint,\n      }\n    }\n    case \'3D000\':\n      return {\n        kind: \'DatabaseDoesNotExist\',\n        db: error.message.split(\' \').at(1)?.split(\'"\').at(1),\n      }\n    case \'28000\':\n      return {\n        kind: \'DatabaseAccessDenied\',\n        db: error.message\n          .split(\',\')\n          .find((s) => s.startsWith(\' database\'))\n          ?.split(\'"\')\n          .at(1),\n      }\n    case \'28P01\':\n      return {\n        kind: \'AuthenticationFailed\',\n        user: error.message.split(\' \').pop()?.split(\'"\').at(1),\n      }\n    case \'40001\':\n      return {\n        kind: \'TransactionWriteConflict\',\n      }\n    case \'42P01\':\n      return {\n        kind: \'TableDoesNotExist\',\n        table: error.message.split(\' \').at(1)?.split(\'"\').at(1),\n      }\n    case \'42703\':\n      return {\n        kind: \'ColumnNotFound\',\n        column: error.message.split(\' \').at(1)?.split(\'"\').at(1),\n      }\n    case \'42P04\':\n      return {\n        kind: \'DatabaseAlreadyExists\',\n        db: error.message.split(\' \').at(1)?.split(\'"\').at(1),\n      }\n    case \'53300\':\n      return {\n        kind: \'TooManyConnections\',\n        cause: error.message,\n      }\n    default:\n      return {\n        kind: \'postgres\',\n        code: error.code ?? \'N/A\',\n        severity: error.severity ?? \'N/A\',\n        message: error.message,\n        detail: error.detail,\n        column: error.column,\n        hint: error.hint,\n      }\n  }\n}\n\nfunction isDriverError(error: any): error is DatabaseError {\n  return (\n    typeof error.code === \'string\' &&\n    typeof error.message === \'string\' &&\n    typeof error.severity === \'string\' &&\n    (typeof error.detail === \'string\' || error.detail === undefined) &&\n    (typeof error.column === \'string\' || error.column === undefined) &&\n    (typeof error.hint === \'string\' || error.hint === undefined)\n  )\n}\n\ntype SocketError = Error & {\n  code: \'ENOTFOUND\' | \'ECONNREFUSED\' | \'ECONNRESET\' | \'ETIMEDOUT\'\n  syscall: string\n  errno: number\n  address?: string | undefined\n  port?: number | undefined\n  hostname?: string | undefined\n}\n\nfunction mapSocketError(error: SocketError): MappedError {\n  switch (error.code) {\n    case \'ENOTFOUND\':\n    case \'ECONNREFUSED\':\n      return {\n        kind: \'DatabaseNotReachable\',\n        host: error.address ?? error.hostname,\n        port: error.port,\n      }\n    case \'ECONNRESET\':\n      return {\n        kind: \'ConnectionClosed\',\n      }\n    case \'ETIMEDOUT\':\n      return {\n        kind: \'SocketTimeout\',\n      }\n  }\n}\n\nfunction isSocketError(error: any): error is Error & {\n  code: \'ENOTFOUND\' | \'ECONNREFUSED\' | \'ECONNRESET\' | \'ETIMEDOUT\'\n  syscall: string\n  errno: number\n  address?: string\n  port?: number\n  hostname?: string\n} {\n  return (\n    typeof error.code === \'string\' &&\n    typeof error.syscall === \'string\' &&\n    typeof error.errno === \'number\' &&\n    SOCKET_ERRORS.has(error.code as string)\n  )\n}\n\nfunction isTlsError(error: any): error is Error & { code?: string } {\n  if (typeof error.code === \'string\') {\n    return TLS_ERRORS.has(error.code as string)\n  }\n\n  //Base Errors thrown by pg.Connection.connect() when SSL is enabled\n  //but the server responds with error code S or N\n  switch (error.message) {\n    case \'The server does not support SSL connections\':\n    case \'There was an error establishing an SSL connection\':\n      return true\n  }\n\n  return false\n}\n',
        }
